import { useState } from "react";
import PageHeader from "../components/PageHeader";
import VoiceInputButton from "../components/VoiceInputButton";
import { createSymptomLog } from "../services/api";

export default function SymptomsPage() {
  const [form, setForm] = useState({ symptom_text: "", source: "text" });
  const [result, setResult] = useState(null);

  const handleSubmit = async (event) => {
    event.preventDefault();
    const data = await createSymptomLog(form);
    setResult(data);
    setForm({ symptom_text: "", source: "text" });
  };

  return (
    <>
      <PageHeader title="Symptom Checker" description="Describe symptoms by text or voice and get a guided, context-aware response." />
      <div className="split-layout single-focus">
        <div className="panel">
          <form onSubmit={handleSubmit}>
            <div className="field">
              <label>Describe your symptoms</label>
              <textarea value={form.symptom_text} onChange={(event) => setForm({ ...form, symptom_text: event.target.value })} />
            </div>
            <div className="button-row">
              <button className="btn btn-primary" type="submit">Analyze</button>
              <VoiceInputButton onTranscript={(text) => setForm({ symptom_text: text, source: "voice" })} />
            </div>
          </form>
        </div>
        <div className="panel">
          <h3 className="section-title">Result</h3>
          {result ? (
            <div className="summary-list">
              <div className="summary-item"><strong>Predicted issue</strong><div>{result.predicted_disease}</div></div>
              <div className="summary-item"><strong>Confidence</strong><div>{(result.confidence_score * 100).toFixed(0)}%</div></div>
              <div className="summary-item"><strong>Suggestions</strong><ul>{result.suggestions.map((item) => <li key={item}>{item}</li>)}</ul></div>
            </div>
          ) : <p className="muted">Your analysis result will appear here.</p>}
        </div>
      </div>
    </>
  );
}
